/* eslint-disable react-hooks/exhaustive-deps */
import React, { useEffect, useState } from "react";
import { BASE } from "./api";

export default function AdminPanel() {
  const [loading, setLoading] = useState(false);
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [reports, setReports] = useState([]);
  const [modal, setModal] = useState(null);
  const [open, setOpen] = useState(false); // ⬅️ NÚT ADMIN

  const token = localStorage.getItem("token");

  // ---------- MODAL ----------
  const showModal = (msg, onYes) => setModal({ msg, onYes });
  const closeModal = () => setModal(null);

  // ---------- FETCH ----------
  const fetchAdminUsers = async () => {
    try {
      const res = await fetch(`${BASE}/api/admin/users`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setUsers(Array.isArray(data) ? data : data.data || []);
    } catch (err) {
      console.error(err);
      setUsers([]);
    }
  };

  const fetchPosts = async () => {
    try {
      const res = await fetch(`${BASE}/api/posts`);
      const data = await res.json();
      const list = data.data?.posts || data.posts || data || [];
      setPosts(Array.isArray(list) ? list : []);
    } catch (err) {
      console.error(err);
      setPosts([]);
    }
  };

  const fetchReports = async () => {
    try {
      const res = await fetch(`${BASE}/api/reports`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setReports(Array.isArray(data.data) ? data.data : []);
    } catch (err) {
      console.error(err);
      setReports([]);
    }
  };

  const refreshAll = async () => {
    setLoading(true);
    await Promise.all([fetchAdminUsers(), fetchPosts(), fetchReports()]);
    setLoading(false);
  };

  useEffect(() => {
    if (open) refreshAll();
  }, [open]);

  // ---------- ACTIONS ----------
  const banUser = (id) =>
    showModal("Ban user này?", async () => {
      await fetch(`${BASE}/api/admin/user/${id}/ban`, {
        method: "PUT",
        headers: { Authorization: `Bearer ${token}` },
      });
      closeModal();
      await fetchAdminUsers();
    });

  const deletePost = (id) =>
    showModal("Xóa bài viết này?", async () => {
      await fetch(`${BASE}/api/admin/post/${id}`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${token}` },
      });
      closeModal();
      await fetchPosts();
    });

  const resolveReport = (id) =>
    showModal("Đánh dấu đã xử lý?", async () => {
      await fetch(`${BASE}/api/admin/report/${id}/resolve`, {
        method: "PUT",
        headers: { Authorization: `Bearer ${token}` },
      });
      closeModal();
      await fetchReports();
    });

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 via-red-50 to-slate-100 px-4 py-6">
      <div className="max-w-6xl mx-auto space-y-6">
        {/* Header with Toggle Button */}
        <div className="flex items-center justify-between">
          <h1 className="text-4xl font-bold text-gray-900 flex items-center gap-3">
            <svg className="w-10 h-10 text-red-600" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 17v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.381z" clipRule="evenodd" />
            </svg>
            Admin Dashboard
          </h1>
          <button
            onClick={() => setOpen(!open)}
            className={`${
              open
                ? 'bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700'
                : 'bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700'
            } text-white font-semibold px-6 py-3 rounded-xl shadow-lg transition-all flex items-center gap-2`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
            {open ? 'Đóng' : 'Mở'} Admin
          </button>
        </div>

        {/* Admin Panel */}
        {open && (
          <div className="space-y-6">
            {/* Refresh Button */}
            <button
              className="w-full bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 text-white font-semibold px-4 py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2"
              onClick={refreshAll}
              disabled={loading}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              {loading ? 'Đang tải...' : 'Làm mới dữ liệu'}
            </button>

            {/* Users Section */}
            <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
              <div className="bg-gradient-to-r from-blue-500 to-blue-600 px-6 py-4 flex items-center gap-3">
                <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M9 6a3 3 0 11-6 0 3 3 0 016 0zM9 6a3 3 0 11-6 0 3 3 0 016 0zM9 6a3 3 0 11-6 0 3 3 0 016 0zM17 6a3 3 0 11-6 0 3 3 0 016 0z" />
                  <path d="M2 13a6 6 0 0112 0v3H2v-3zm6-6h.01M17 13a6 6 0 01-12 0" />
                </svg>
                <h2 className="text-2xl font-bold text-white">Quản lý người dùng ({users.length})</h2>
              </div>
              <div className="divide-y divide-gray-200">
                {users.length === 0 ? (
                  <div className="p-8 text-center text-gray-500">
                    <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 20h5v-2a3 3 0 00-5.856-1.487M15 10a3 3 0 11-6 0 3 3 0 016 0z" />
                    </svg>
                    Không có user
                  </div>
                ) : (
                  users.map((u) => (
                    <div
                      key={u.id}
                      className="px-6 py-4 flex justify-between items-center hover:bg-blue-50 transition-colors"
                    >
                      <div className="flex-1">
                        <p className="font-semibold text-gray-900">{u.full_name || u.username}</p>
                        <p className="text-sm text-gray-600">{u.email}</p>
                        <p className="text-xs text-gray-500 mt-1">ID: {u.id}</p>
                      </div>
                      <button
                        className="bg-red-500 hover:bg-red-600 text-white font-semibold px-4 py-2 rounded-lg transition-all flex items-center gap-2"
                        onClick={() => banUser(u.id)}
                      >
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M13.477 14.89A6 6 0 110 6a6.002 6.002 0 0113.477 8.89z" clipRule="evenodd" />
                        </svg>
                        Ban
                      </button>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* Posts Section */}
            <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
              <div className="bg-gradient-to-r from-purple-500 to-purple-600 px-6 py-4 flex items-center gap-3">
                <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M2 5a2 2 0 012-2h12a2 2 0 012 2v10a2 2 0 01-2 2H4a2 2 0 01-2-2V5z" />
                  <path fillRule="evenodd" d="M3 7a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm0 4a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" />
                </svg>
                <h2 className="text-2xl font-bold text-white">Quản lý bài viết ({posts.length})</h2>
              </div>
              <div className="divide-y divide-gray-200">
                {posts.length === 0 ? (
                  <div className="p-8 text-center text-gray-500">
                    <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                    </svg>
                    Không có bài viết
                  </div>
                ) : (
                  posts.map((p) => (
                    <div key={p.id} className="px-6 py-4 hover:bg-purple-50 transition-colors">
                      <p className="font-semibold text-gray-900 mb-1">{p.content || p.text || '(Không có nội dung)'}</p>
                      <p className="text-sm text-gray-600 mb-3">
                        <svg className="w-4 h-4 inline mr-1" fill="currentColor" viewBox="0 0 20 20">
                          <path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" />
                        </svg>
                        bởi @{p.user?.username || p.User?.username || 'unknown'}
                      </p>
                      <button
                        className="bg-red-500 hover:bg-red-600 text-white font-semibold px-4 py-2 rounded-lg transition-all flex items-center gap-2"
                        onClick={() => deletePost(p.id)}
                      >
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                        </svg>
                        Xóa
                      </button>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* Reports Section */}
            <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
              <div className="bg-gradient-to-r from-orange-500 to-orange-600 px-6 py-4 flex items-center gap-3">
                <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
                <h2 className="text-2xl font-bold text-white">Quản lý báo cáo ({reports.length})</h2>
              </div>
              <div className="divide-y divide-gray-200">
                {reports.length === 0 ? (
                  <div className="p-8 text-center text-gray-500">
                    <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4v2m0 6V9m6 0a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    Không có báo cáo
                  </div>
                ) : (
                  reports.map((r) => (
                    <div key={r.id} className="px-6 py-4 hover:bg-orange-50 transition-colors">
                      <p className="font-semibold text-gray-900 mb-1">Report #{r.id}</p>
                      <p className="text-gray-700 mb-3">{r.reason}</p>
                      <button
                        className="bg-green-500 hover:bg-green-600 text-white font-semibold px-4 py-2 rounded-lg transition-all flex items-center gap-2"
                        onClick={() => resolveReport(r.id)}
                      >
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                        </svg>
                        Xác nhận xử lý
                      </button>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}

        {/* Confirmation Modal */}
        {modal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 backdrop-blur-sm">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6 space-y-4 animate-in fade-in zoom-in-95">
              <div className="flex items-center gap-3">
                <svg className="w-6 h-6 text-orange-600" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
                <p className="text-lg font-semibold text-gray-900">{modal.msg}</p>
              </div>
              <div className="flex gap-3 pt-4">
                <button
                  className="flex-1 bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 text-white font-semibold px-4 py-2 rounded-lg transition-all"
                  onClick={() => modal.onYes()}
                >
                  Xác nhận
                </button>
                <button
                  className="flex-1 bg-gray-300 hover:bg-gray-400 text-gray-800 font-semibold px-4 py-2 rounded-lg transition-all"
                  onClick={closeModal}
                >
                  Hủy
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
